import * as codeinfra from "@codeinfra/codeinfra";

const stackName = codeinfra.getStack();
if (!stackName) {
    // We can't check for a specific stack name, since it is autogenerated by the test framework.  But
    // we *can* verify that it isn't blank.
    throw new Error("Empty codeinfra.getStack() at runtime");
}

const expName = "stack_project_name";
const projName = codeinfra.getProject();
if (projName !== expName) {
    throw new Error(`Unexpected codeinfra.getProject(); wanted '${expName}', got '${projName}'`);
}

const expOrgName =  process.env["CODEINFRA_TEST_OWNER"];
// If we're running serviceless don't check the org name
if (expOrgName !== undefined) {
    const orgName = codeinfra.getOrganization();
    if (orgName !== expOrgName) {
        throw new Error(`Unexpected codeinfra.getOrganization(); wanted '${expOrgName}', got '${orgName}'`);
    }
}
